import React, { useEffect, useState } from 'react';
import { alertService } from '../services/api';
import { Alert } from '../types';
import { useNavigate } from 'react-router-dom';
import { Eye, Sparkles } from 'lucide-react';

const severityColors: Record<string, string> = {
  CRITIQUE: 'bg-red-50 text-red-600 border border-red-200',
  HAUTE: 'bg-orange-50 text-orange-600 border border-orange-200',
  ÉLEVÉE: 'bg-orange-50 text-orange-600 border border-orange-200',
  MOYENNE: 'bg-yellow-50 text-yellow-700 border border-yellow-200',
  FAIBLE: 'bg-blue-50 text-blue-600 border border-blue-200',
};

const statusColors: Record<string, string> = {
  'Nouveau': 'bg-cyan-50 text-cyan-700 border border-cyan-200',
  'En cours': 'bg-amber-50 text-amber-700 border border-amber-200',
  'Résolu': 'bg-green-50 text-green-700 border border-green-200',
  'Faux Positif': 'bg-gray-50 text-gray-500 border border-gray-200',
};

const AlertList: React.FC = () => {
  const [alerts, setAlerts] = useState<Alert[]>([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    fetchAlerts();
  }, []);

  const fetchAlerts = async () => {
    try {
      const data = await alertService.getAll();
      setAlerts(data.alerts || []);
    } catch (err) {
      console.error('Failed to fetch alerts:', err);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="space-y-2">
      {alerts.map((alert) => {
        const severity = alert.severity?.toUpperCase() || 'FAIBLE';
        const status = alert.status || 'Nouveau';
        const ip = alert.details?.src_ip || alert.details?.sourceIp || '-';
        const date = new Date(alert.createdAt);
        const dateStr = date.toLocaleDateString('fr-FR');
        const timeStr = date.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: true });
        const alertId = alert._id?.substring(0, 10)?.toUpperCase() || alert._id;

        return (
          <div
            key={alert._id}
            className="flex items-center gap-6 bg-white rounded-xl px-6 py-4 border border-gray-100 shadow-[0_1px_3px_rgba(0,0,0,0.04)] hover:shadow-md transition-shadow cursor-pointer"
            onClick={() => navigate(`/alerts/${alert._id}`)}
          >
            {/* Severity Badge */}
            <div className="w-[100px] flex-shrink-0">
              <span className={`inline-block px-3 py-1 rounded text-[10px] font-extrabold uppercase tracking-wider ${severityColors[severity] || severityColors['FAIBLE']}`}>
                {severity}
              </span>
            </div>

            {/* Title & ID */}
            <div className="flex-1 min-w-0">
              <p className="text-sm font-bold text-[#1f2937] truncate">{alert.title}</p>
              <p className="text-[11px] font-semibold text-gray-400 mt-0.5">DEF-{alertId}</p>
            </div>

            {/* Source & IP */}
            <div className="w-[160px] flex-shrink-0 text-right">
              <p className="text-sm font-bold text-[#1f2937]">{alert.source}</p>
              <p className="text-[11px] font-semibold text-gray-400 mt-0.5">{ip}</p>
            </div>

            {/* Date */}
            <div className="w-[100px] flex-shrink-0 text-right">
              <p className="text-sm font-bold text-[#1f2937]">{dateStr}</p>
              <p className="text-[11px] font-semibold text-gray-400 mt-0.5">{timeStr}</p>
            </div>

            {/* Status Badge */}
            <div className="w-[110px] flex-shrink-0">
              <span className={`inline-block px-3 py-1 rounded text-[10px] font-extrabold uppercase tracking-wider ${statusColors[status] || statusColors['Nouveau']}`}>
                {status.toUpperCase()}
              </span>
            </div>

            {/* IA Link */}
            <div className="w-[130px] flex-shrink-0 text-center">
              <button
                onClick={(e) => { e.stopPropagation(); }}
                className="text-[10px] font-bold text-pink-400 hover:text-pink-600 flex items-center gap-1"
              >
                <Sparkles className="h-3 w-3" />
                IA AUTOMATISÉE
              </button>
            </div>

            {/* Eye Icon */}
            <div className="flex-shrink-0">
              <Eye className="h-5 w-5 text-gray-300 hover:text-gray-500" />
            </div>
          </div>
        );
      })}

      {alerts.length === 0 && (
        <div className="rounded-xl border bg-white p-12 text-center text-gray-400 font-semibold">
          Aucune alerte trouvée.
        </div>
      )}
    </div>
  );
};

export default AlertList;
